// ==== PULL TO REFRESH HOOK ====
const usePullToRefresh = (onRefresh) => {
    const [pulling, setPulling] = useState(false);
    const [pullY, setPullY] = useState(0);
    const [refreshing, setRefreshing] = useState(false);
    const startY = useRef(0);
    const containerRef = useRef(null);
    const threshold = 80;
    const onTouchStart = useCallback(e => {
        if (refreshing) return;
        const el = containerRef.current;
        if (el && el.scrollTop <= 0) startY.current = e.touches[0].clientY;
        else startY.current = 0;
    }, [refreshing]);
    const onTouchMove = useCallback(e => {
        if (!startY.current || refreshing) return;
        const dy = e.touches[0].clientY - startY.current;
        if (dy > 0) { setPulling(true); setPullY(Math.min(dy * 0.4, 120)); if (dy > 10) e.preventDefault(); }
    }, [refreshing]);
    const onTouchEnd = useCallback(async () => {
        if (pullY >= threshold && onRefresh && !refreshing) {
            setRefreshing(true); setPullY(50);
            try { await onRefresh(); } finally { setRefreshing(false); }
        }
        setPulling(false); setPullY(0); startY.current = 0;
    }, [pullY, onRefresh, refreshing]);
    const indicatorEl = (pullY > 0 || refreshing) ? (
        <div style={{textAlign:'center',overflow:'hidden',transition:pulling?'none':'height 0.3s',height:refreshing?50:pullY,display:'flex',alignItems:'center',justifyContent:'center',gap:8}}>
            {refreshing ? <F1MiniLoader/> : (<>
                <div style={{transform:`rotate(${pullY*3}deg)`,fontSize:24,opacity:pullY/threshold}}>🏎️</div>
                <div style={{fontSize:11,color:'rgba(255,255,255,0.4)'}}>{pullY >= threshold ? 'Отпусти для обновления!' : 'Потяни вниз'}</div>
            </>)}
        </div>
    ) : null;
    return {containerRef, onTouchStart, onTouchMove, onTouchEnd, indicatorEl};
};

