const circuitFlags = {
    'albert_park':'🇦🇺','shanghai':'🇨🇳','suzuka':'🇯🇵','bahrain':'🇧🇭',
    'jeddah':'🇸🇦','miami':'🇺🇸','imola':'🇮🇹','monaco':'🇲🇨',
    'catalunya':'🇪🇸','villeneuve':'🇨🇦','red_bull_ring':'🇦🇹','silverstone':'🇬🇧',
    'spa':'🇧🇪','hungaroring':'🇭🇺','zandvoort':'🇳🇱','monza':'🇮🇹',
    'baku':'🇦🇿','marina_bay':'🇸🇬','cota':'🇺🇸','americas':'🇺🇸','rodriguez':'🇲🇽',
    'interlagos':'🇧🇷','las_vegas':'🇺🇸','vegas':'🇺🇸','lusail':'🇶🇦','losail':'🇶🇦','yas_marina':'🇦🇪',
    'madring':'🇪🇸'
};

const countryFlag = (code) => {
    if (!code) return '';
    return String.fromCodePoint(...[...code.toUpperCase()].map(c => 0x1F1E6 + c.charCodeAt(0) - 65));
};
const FlagImg = ({code, size}) => {
    if (!code || code.length !== 2) return null;
    const s = size || 20;
    return <img src={`https://flagcdn.com/${Math.round(s*2)}x${Math.round(s*1.5)}/${code.toLowerCase()}.png`} alt={code} style={{width:s,height:Math.round(s*0.75),objectFit:'cover',verticalAlign:'middle',borderRadius:2}} onError={e=>{e.target.style.display='none'}}/>;
};
const toMSK = (utcTime) => {
    if (!utcTime) return '';
    const [h, m] = utcTime.replace('Z','').split(':');
    const msk = (parseInt(h) + 3) % 24;
    return `${String(msk).padStart(2,'0')}:${m} МСК`;
};

