const QuizGame = ({onBack}) => {
    const [state, setState] = useState('ready');
    const [questions, setQuestions] = useState([]);
    const [qIdx, setQIdx] = useState(0);
    const [selected, setSelected] = useState(null);
    const [score, setScore] = useState(0);
    const [result, setResult] = useState(null);
    const totalQ = 5;

    const generateQuestions = () => {
        const easy = QUIZ_BANK.filter(q=>q.d===1).sort(()=>Math.random()-0.5).slice(0,2);
        const med = QUIZ_BANK.filter(q=>q.d===2).sort(()=>Math.random()-0.5).slice(0,2);
        const hard = QUIZ_BANK.filter(q=>q.d===3).sort(()=>Math.random()-0.5).slice(0,1);
        return [...easy,...med,...hard];
    };

    const startGame = () => { setQuestions(generateQuestions()); setQIdx(0); setScore(0); setSelected(null); setResult(null); setState('playing'); };

    const answer = (idx) => {
        if (selected!==null) return;
        setSelected(idx);
        const isCorrect = idx===questions[qIdx].a;
        const newScore = score + (isCorrect?1:0);
        if(isCorrect) setScore(s=>s+1);
        setTimeout(()=>{
            if (qIdx+1<totalQ) { setQIdx(i=>i+1); setSelected(null); }
            else {
                setState('finished');
                api.post('/api/games/result',{game_type:'quiz',score:newScore}).then(res=>setResult(res));
            }
        }, 1200);
    };

    const diffLabel = (d) => d===1?'Легко':d===2?'Средне':'Сложно';
    const diffColor = (d) => d===1?'#27F4D2':d===2?'#FF8000':'#e10600';

    return (
        <div className="page-container fade-in" style={{padding:'20px 16px'}}>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:20}}>
                <div onClick={onBack} style={{cursor:'pointer',fontSize:14,color:'var(--f1-text-muted)'}}>← Назад</div>
                <div style={{fontWeight:800,fontSize:18}}>🧠 F1 Квиз</div>
                <div style={{width:50}}/>
            </div>
            {state==='ready' && (
                <div style={{textAlign:'center'}}>
                    <div style={{fontSize:60,marginBottom:20}}>🧠</div>
                    <div style={{fontSize:14,color:'var(--f1-text-secondary)',marginBottom:8}}>{totalQ} вопросов об истории F1</div>
                    <div style={{fontSize:12,color:'var(--f1-text-muted)',marginBottom:24}}>2 лёгких · 2 средних · 1 сложный</div>
                    <div onClick={startGame} style={{padding:'16px 40px',borderRadius:14,background:'#6692FF',fontWeight:800,fontSize:18,cursor:'pointer',display:'inline-block',fontFamily:'inherit',border:'none',color:'#fff'}}>СТАРТ</div>
                </div>
            )}
            {state==='playing' && questions[qIdx] && (
                <div>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
                        <div style={{fontSize:12,color:'var(--f1-text-muted)'}}>Вопрос {qIdx+1}/{totalQ} · Счёт: {score}</div>
                        <div style={{fontSize:10,fontWeight:700,color:diffColor(questions[qIdx].d),background:`${diffColor(questions[qIdx].d)}22`,padding:'3px 8px',borderRadius:6}}>{diffLabel(questions[qIdx].d)}</div>
                    </div>
                    <div style={{fontSize:16,fontWeight:700,marginBottom:20,textAlign:'center',lineHeight:1.4}}>{questions[qIdx].q}</div>
                    {questions[qIdx].o.map((opt,idx)=>{
                        let bg = 'rgba(255,255,255,0.06)';
                        if (selected!==null) { if(idx===questions[qIdx].a) bg='rgba(0,200,0,0.2)'; else if(idx===selected) bg='rgba(255,0,0,0.2)'; }
                        return (
                            <div key={idx} onClick={()=>answer(idx)} style={{padding:'14px 16px',marginBottom:8,borderRadius:12,background:bg,cursor:selected!==null?'default':'pointer',fontWeight:600,fontSize:14,transition:'all 0.2s'}}>
                                {opt}
                            </div>
                        );
                    })}
                </div>
            )}
            {state==='finished' && (
                <div style={{textAlign:'center'}}>
                    <div style={{fontSize:48,marginBottom:12}}>{score>=4?'🏆':score>=2?'👏':'📚'}</div>
                    <div style={{fontSize:32,fontWeight:800,color:'#6692FF'}}>{score}/{totalQ}</div>
                    <div style={{fontSize:14,color:'var(--f1-text-secondary)',marginTop:4}}>{score>=4?'Настоящий знаток!':score>=2?'Неплохо!':'Почитай про F1!'}</div>
                    <div style={{display:'flex',gap:12,justifyContent:'center',marginTop:24}}>
                        <div onClick={startGame} style={{padding:'12px 24px',borderRadius:12,background:'#6692FF',fontWeight:700,cursor:'pointer',color:'#fff'}}>Ещё раз</div>
                        <div onClick={onBack} style={{padding:'12px 24px',borderRadius:12,background:'rgba(255,255,255,0.08)',fontWeight:700,cursor:'pointer'}}>Назад</div>
                    </div>
                </div>
            )}
        </div>
    );
};

const GamesPage = ({onChange}) => {
    const [status, setStatus] = useState(null);
    const [activeGame, setActiveGame] = useState(null);

    useEffect(()=>{ api.get('/api/games/status').then(setStatus); }, []);

    const goBack = () => { setActiveGame(null); api.get('/api/games/status').then(setStatus); };

    if (activeGame==='pit_stop') return <PitStopGame onBack={goBack}/>;
    if (activeGame==='top_trumps') return <TopTrumpsGame onBack={goBack}/>;
    if (activeGame==='reaction') return <ReactionGame onBack={goBack}/>;
    if (activeGame==='quiz') return <QuizGame onBack={goBack}/>;

    const games = [
        {id:'pit_stop',icon:'🔧',name:'Пит-стоп',desc:'Смени шины быстрее всех!',color:'#e10600'},
        {id:'top_trumps',icon:'🃏',name:'Top Trumps',desc:'Карточная битва пилотов F1',color:'#FFD700'},
        {id:'reaction',icon:'🚦',name:'Реакция',desc:'Стартуй по зелёному!',color:'#27F4D2'},
        {id:'quiz',icon:'🧠',name:'F1 Квиз',desc:'Проверь свои знания',color:'#6692FF'},
    ];

    return (
        <div className="page-container fade-in" style={{padding:'12px 16px'}}>
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:16}}>
                <h2 style={{fontSize:22,fontWeight:900}}>🎮 Мини-игры</h2>
                {onChange && <div onClick={()=>onChange('home')} style={{cursor:'pointer',fontSize:13,color:'var(--f1-text-muted)'}}>← Главная</div>}
            </div>
            {games.map(g => {
                const st = status?.games?.[g.id];
                const canPlay = st?.can_play!==false;
                const cooldown = st?.seconds_left;
                return (
                    <div key={g.id} className="card" onClick={()=>canPlay&&setActiveGame(g.id)}
                         style={{display:'flex',alignItems:'center',gap:14,padding:16,marginBottom:8,
                             borderLeft:`4px solid ${g.color}`,opacity:canPlay?1:0.5,cursor:canPlay?'pointer':'default'}}>
                        <div style={{fontSize:32}}>{g.icon}</div>
                        <div style={{flex:1}}>
                            <div style={{fontWeight:700,fontSize:16}}>{g.name}</div>
                            <div style={{fontSize:12,color:'var(--f1-text-muted)',marginTop:2}}>{g.desc}</div>
                        </div>
                        {!canPlay && cooldown>0 && (
                            <div style={{fontSize:11,color:'var(--f1-text-muted)',textAlign:'right'}}>
                                ⏳ {Math.floor(cooldown/3600)}ч {Math.floor((cooldown%3600)/60)}м
                            </div>
                        )}
                        {canPlay && <div style={{fontSize:13,fontWeight:700,color:g.color}}>ИГРАТЬ →</div>}
                    </div>
                );
            })}
        </div>
    );
};

// ==== PUBLIC LOGIN (Login Widget) ====
const PublicLoginPage = ({ onLogin }) => {
    const containerRef = useRef(null);
    useEffect(() => {
        if (!containerRef.current) return;
        // Telegram Login Widget callback
        window.__onTelegramAuth = (tgUser) => {
            // Build query string from widget data
            const params = new URLSearchParams();
            Object.keys(tgUser).forEach(k => params.set(k, tgUser[k]));
            const qs = params.toString();
            localStorage.setItem('f1hub_auth_token', qs);
            onLogin(tgUser);
        };
        const script = document.createElement('script');
        script.src = 'https://telegram.org/js/telegram-widget.js?22';
        script.setAttribute('data-telegram-login', 'F1_egor_bot');
        script.setAttribute('data-size', 'large');
        script.setAttribute('data-radius', '12');
        script.setAttribute('data-onauth', '__onTelegramAuth(user)');
        script.setAttribute('data-request-access', 'write');
        script.async = true;
        containerRef.current.appendChild(script);
    }, []);
    return (
        <div style={{height:'100dvh',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:24,padding:32}}>
            <div style={{fontSize:28,fontWeight:900}}>F1 <span style={{color:'var(--f1-red)'}}>Hub</span></div>
            <div style={{fontSize:14,color:'var(--f1-text-secondary)',textAlign:'center',maxWidth:300,lineHeight:1.5}}>
                Войдите через Telegram, чтобы получить доступ к прогнозам, играм и персональной статистике
            </div>
            <div ref={containerRef}></div>
            <button onClick={() => onLogin(null)} className="btn-primary" style={{marginTop:8,background:'transparent',border:'1px solid var(--f1-border)',fontSize:13,padding:'10px 20px'}}>
                Продолжить без входа
            </button>
        </div>
    );
};

// ==== MAIN APP ====
const App = () => {
    const [tab, setTab] = useState('home');
    const [currentSeason, setCurrentSeason] = useState(2026);
    const [loading, setLoading] = useState(true);
    const [user, setUser] = useState(null);
    const [showLogin, setShowLogin] = useState(false);
    const [nextRace, setNextRace] = useState(null);
    const [lastRace, setLastRace] = useState(null);
    const [schedule, setSchedule] = useState(null);
    const [driversStandings, setDriversStandings] = useState(null);
    const [constructorsStandings, setConstructorsStandings] = useState(null);
    const [session, setSession] = useState(null);
    const [positions, setPositions] = useState(null);
    const [timing, setTiming] = useState(null);
    const [weather, setWeather] = useState(null);
    const [raceControl, setRaceControl] = useState(null);
    const [streams, setStreams] = useState(null);
    const [liveBroadcasts, setLiveBroadcasts] = useState([]);
    const [seasonResults, setSeasonResults] = useState(null);
    const [selectedRound, setSelectedRound] = useState(null);
    const [raceDetailTab, setRaceDetailTab] = useState('race');
    const [selectedArticle, setSelectedArticle] = useState(null);
    const [spoilerFree, setSpoilerFree] = useState(() => localStorage.getItem('f1hub_spoiler_free') === 'true');
    const isLive = session?.is_live;
    const toggleSpoiler = () => { const v = !spoilerFree; setSpoilerFree(v); localStorage.setItem('f1hub_spoiler_free', String(v)); };

    useEffect(() => {
        (async () => {
            if (IS_WEBAPP) {
                const [u, s] = await Promise.all([api.get('/api/user/me'), api.get('/api/live/session')]);
                setUser(u); setSession(s); setLoading(false);
                if (u?.user_id) {
                    api.get('/api/user/is-admin').then(d => {
                        if (d?.is_admin) window.__F1_ADMIN_IDS = [u.user_id];
                    }).catch(()=>{});
                }
            } else {
                // Public site: try stored auth, otherwise load anonymously
                const token = localStorage.getItem('f1hub_auth_token');
                const s = await api.get('/api/live/session');
                setSession(s);
                if (token) {
                    const u = await api.get('/api/user/me');
                    if (u) { setUser(u); setLoading(false); return; }
                    // Token expired, clear it
                    localStorage.removeItem('f1hub_auth_token');
                }
                setLoading(false);
            }
        })();
    }, []);

    // Public site: listen for auth-expired events
    useEffect(() => {
        if (IS_WEBAPP) return;
        const handler = () => {
            localStorage.removeItem('f1hub_auth_token');
            setUser(null);
            setShowLogin(true);
        };
        window.addEventListener('f1:auth-expired', handler);
        return () => window.removeEventListener('f1:auth-expired', handler);
    }, []);

    useEffect(() => {
        if (loading) return;
        const s = currentSeason;
        setNextRace(null); setLastRace(null); setDriversStandings(null); setConstructorsStandings(null); setSchedule(null); setSeasonResults(null);
        Promise.all([api.get(`/api/home?season=${s}`),api.get(`/api/standings/drivers?season=${s}`),api.get(`/api/standings/constructors?season=${s}`),api.get(`/api/schedule?season=${s}`),api.get('/api/streams'),api.get(`/api/season/${s}/results`),api.get('/api/broadcasts/live')]).then(([home,ds,cs,sched,str,sr,lb])=>{
            if(home){setNextRace(home.next_race);setLastRace(home.last_race);}
            setDriversStandings(ds); setConstructorsStandings(cs); setSchedule(sched); setStreams(str); setSeasonResults(sr); if(lb?.broadcasts) setLiveBroadcasts(lb.broadcasts);
        });
    }, [loading, currentSeason]);

    useEffect(() => {
        if (tab !== 'live') return;
        const fetchLive = async () => { const d=await api.get('/api/live/dashboard'); if(d){setSession(d.session);setPositions(d.positions);setTiming(d.timing);setWeather(d.weather);setRaceControl(d.race_control);} };
        fetchLive();
        const iv = setInterval(fetchLive, isLive ? 10000 : 30000);
        return () => clearInterval(iv);
    }, [tab, isLive]);

    useEffect(() => {
        if (!tg) return;
        if (tab === 'article') {
            tg.BackButton?.show();
            const h = () => { setSelectedArticle(null); setTab('news'); };
            tg.BackButton?.onClick(h);
            return () => tg.BackButton?.offClick(h);
        } else if (tab === 'raceDetail') {
            tg.BackButton?.show();
            const h = () => setTab('schedule');
            tg.BackButton?.onClick(h);
            return () => tg.BackButton?.offClick(h);
        } else if (tab === 'analytics') {
            tg.BackButton?.show();
            const h = () => setTab('live');
            tg.BackButton?.onClick(h);
            return () => tg.BackButton?.offClick(h);
        } else if (tab !== 'home') {
            tg.BackButton?.show();
            const h = () => setTab('home');
            tg.BackButton?.onClick(h);
            return () => tg.BackButton?.offClick(h);
        } else {
            tg.BackButton?.hide();
        }
    }, [tab]);

    if (loading) return (
        <div style={{height:'100dvh',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:16}}>
            <div style={{fontSize:22,fontWeight:900}}>F1 <span style={{color:'var(--f1-red)'}}>Hub</span></div>
            <div className="f1-lights"><div className="f1-light"/><div className="f1-light"/><div className="f1-light"/><div className="f1-light"/><div className="f1-light"/></div>
        </div>
    );

    // Public site: show login page when requested or for auth-required tabs
    if (!IS_WEBAPP && showLogin) {
        return <PublicLoginPage onLogin={(tgUser) => {
            setShowLogin(false);
            if (tgUser) {
                api.get('/api/user/me').then(u => { if (u) setUser(u); });
            }
        }} />;
    }

    // Public: tabs requiring auth → prompt login
    const needsAuth = !IS_WEBAPP && !user && (tab === 'predict' || tab === 'profile' || tab === 'games');
    if (needsAuth) {
        return <PublicLoginPage onLogin={(tgUser) => {
            if (tgUser) {
                api.get('/api/user/me').then(u => { if (u) setUser(u); });
            } else {
                setTab('home');
            }
        }} />;
    }

    const renderTab = () => {
        switch(tab) {
            case 'home': return <HomePage nextRace={nextRace} lastRace={lastRace} standings={driversStandings} user={user} streams={streams} seasonResults={seasonResults} schedule={schedule} onChange={setTab} season={currentSeason} onSeasonChange={setCurrentSeason} spoilerFree={spoilerFree && currentSeason === 2026} onToggleSpoiler={toggleSpoiler} liveBroadcasts={liveBroadcasts} onRaceClick={(round,dtab)=>{setSelectedRound(round);setRaceDetailTab(dtab||'race');setTab('raceDetail');}} onRefresh={async()=>{const[home,ds]=await Promise.all([api.get(`/api/home?season=${currentSeason}`),api.get(`/api/standings/drivers?season=${currentSeason}`)]);if(home){setNextRace(home.next_race);setLastRace(home.last_race);}if(ds)setDriversStandings(ds);}}/>;
            case 'live': return <LivePage session={session} positions={positions} timing={timing} weather={weather} raceControl={raceControl} onChange={setTab} onRefresh={async()=>{const d=await api.get('/api/live/dashboard');if(d){setSession(d.session);setPositions(d.positions);setTiming(d.timing);setWeather(d.weather);setRaceControl(d.race_control);}}}/>;
            case 'news': return <NewsPage onArticleClick={(url)=>{setSelectedArticle(url);setTab('article');}}/>;
            case 'article': return <ArticlePage articleUrl={selectedArticle} onBack={()=>{setSelectedArticle(null);setTab('news');}}/>;
            case 'schedule': return <SchedulePage seasonResults={seasonResults} schedule={schedule} season={currentSeason} onRaceClick={(round,dtab)=>{setSelectedRound(round);setRaceDetailTab(dtab||'race');setTab('raceDetail');}} spoilerFree={spoilerFree}/>;
            case 'raceDetail': return <RaceDetailPage race={seasonResults?.races?.find(r=>r.round===selectedRound) || schedule?.races?.find(r=>r.round===selectedRound)} onBack={()=>setTab('schedule')} season={currentSeason} spoilerFree={spoilerFree && currentSeason === 2026} allRaces={seasonResults?.races} defaultTab={raceDetailTab}/>;
            case 'standings': return <StandingsPage driversStandings={driversStandings} constructorsStandings={constructorsStandings} season={currentSeason} spoilerFree={spoilerFree && currentSeason === 2026} onBack={()=>setTab('home')} onRefresh={async()=>{const[ds,cs]=await Promise.all([api.get(`/api/standings/drivers?season=${currentSeason}`),api.get(`/api/standings/constructors?season=${currentSeason}`)]);if(ds)setDriversStandings(ds);if(cs)setConstructorsStandings(cs);}}/>;
            case 'predict': return <PredictionsPage user={user}/>;
            case 'profile': return <ProfilePage user={user}/>;
            case 'analytics': return <AnalyticsPage/>;
            case 'games': return <GamesPage onChange={setTab}/>;
            default: return null;
        }
    };

    return (<>{renderTab()}<BottomNav active={tab} onChange={setTab} isLive={isLive}/></>);
};

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App/>);
